class Solution:
    def heapifyInsertion(self, nums, n):
        for i in range(n - 1, 0, -1):
            largest = i
            for j in range(2 * i + 1, n):
                if nums[largest] < nums[j]:
                    largest = j
            if nums[largest] != i:
                nums[i], nums[largest] = nums[largest], nums[i]

        return nums

