class Solution {
public:
    vector<int> heapifyInsertion(vector<int> &nums, int n) {
        for (int i = n - 1; i >= 0; i--) {
            largest = i;
            for (int j = 2 * i + 1; j < n; j++) {
                if (nums[largest] < nums[j]) {
                    largest = j;
                }
            }
            if (nums[largest] != i) {
                swap(nums[i], nums[largest]);
            }
        }
        return nums;
    }
};
